// Sub-workflow compartido por todos los canales (FB, IG, TG, TT)
// Recibe: platform, tenantId, senderId, senderName, messageText, businessConfig, references
var input = $('Recibir Datos del Canal').first().json;
var bc = input.businessConfig || {};
var refs = input.references || [];

// Catalogo de productos
var catalogLines = (bc.catalog || []).map(function(p) {
  var line = '- ' + p.name;
  if (p.price) line += ' | $' + Number(p.price).toLocaleString('es-CO');
  if (p.category) line += ' | ' + p.category;
  if (p.available === false) line += ' [NO DISPONIBLE]';
  if (p.description) line += ': ' + p.description;
  return line;
});

// FAQ
var faqLines = (bc.faq || []).map(function(f) {
  return 'P: ' + f.question + '\nR: ' + f.answer;
});

// Referencias externas activas (para RAG)
var refsText = '';
if (refs.length > 0) {
  refsText = '\n\nFUENTES DE REFERENCIA REGISTRADAS (el sistema puede consultarlas para responder con datos reales):\n';
  refs.forEach(function(r) {
    refsText += '- [' + r.type.toUpperCase() + '] ' + r.name + ': ' + r.url;
    if (r.description) refsText += ' — ' + r.description;
    refsText += '\n';
  });
}

// Horario
var tz = bc.businessHours && bc.businessHours.timezone ? bc.businessHours.timezone : 'America/Bogota';
var now = new Date();
var localTime = new Intl.DateTimeFormat('es-CO', { timeZone: tz, hour: '2-digit', minute: '2-digit', hourCycle: 'h23' }).format(now);
var dayName = new Intl.DateTimeFormat('es-CO', { timeZone: tz, weekday: 'long' }).format(now);
var schedule = bc.businessHours && bc.businessHours.schedule ? bc.businessHours.schedule : [];
var todaySchedule = schedule.find(function(d) {
  return (d.day || '').toLowerCase() === dayName.toLowerCase();
});
var parts = localTime.split(':');
var nowMins = parseInt(parts[0], 10) * 60 + parseInt(parts[1], 10);
var inHours = true;
if (todaySchedule && todaySchedule.isOpen) {
  var op = (todaySchedule.open || '00:00').split(':');
  var cl = (todaySchedule.close || '23:59').split(':');
  inHours = nowMins >= (parseInt(op[0],10)*60+parseInt(op[1],10)) && nowMins <= (parseInt(cl[0],10)*60+parseInt(cl[1],10));
} else if (todaySchedule && !todaySchedule.isOpen) {
  inHours = false;
}

// Plataforma label
var platformLabel = { facebook: 'Facebook Messenger', instagram: 'Instagram Direct', telegram: 'Telegram', tiktok: 'TikTok' }[input.platform] || input.platform;

// Clasificacion CRITICA
var classificationInstruction =
  'INSTRUCCION CRITICA — DEBES SEGUIRLA OBLIGATORIAMENTE:\n' +
  'Al FINAL de tu respuesta al cliente, SIEMPRE agrega este bloque exacto:\n' +
  '<JSON>\n' +
  '{"intent":"INTENT","confidence":SCORE,"suggested_response":"TU_RESPUESTA"}\n' +
  '</JSON>\n\n' +
  'Donde INTENT es UNO de: ventas | soporte | agendamiento | informacion | humano | fallback\n' +
  'Donde SCORE es un numero entre 0.0 y 1.0\n\n';

// Escapar { } para LangChain PromptTemplate
var oe = '{{';
var ce = '}}';
var rawSystem =
  classificationInstruction +
  '=== INSTRUCCIONES DEL NEGOCIO ===\n' +
  (bc.aiInstructions || 'Eres un asistente de atencion al cliente profesional y amable.') +
  '\n\nNombre del negocio: ' + (bc.businessName || '') +
  '\nCanal de atencion: ' + platformLabel +
  '\nTono: ' + (bc.tone || 'amigable') +
  '\nIdioma: ' + (bc.language || 'es') +
  '\n\nCATALOGO DE PRODUCTOS:\n' + (catalogLines.length > 0 ? catalogLines.join('\n') : 'Sin productos configurados.') +
  '\n\nPREGUNTAS FRECUENTES:\n' + (faqLines.length > 0 ? faqLines.join('\n\n') : 'Sin FAQ.') +
  (bc.paymentMethods && bc.paymentMethods.length > 0 ? '\n\nMetodos de pago: ' + bc.paymentMethods.join(', ') : '') +
  (bc.location ? '\n\nUbicacion: ' + bc.location : '') +
  refsText +
  '\n\nAcciones permitidas: ' + (bc.allowedActions || []).join(', ') +
  '\nRestricciones: ' + (bc.restrictions || []).join(', ') +
  '\n\nCliente en esta conversacion: ' + (input.senderName || 'Cliente');

var systemMessage = rawSystem.split('{').join(oe).split('}').join(ce);

return [{
  json: {
    platform: input.platform,
    tenantId: input.tenantId,
    senderId: input.senderId,
    senderName: input.senderName || 'Cliente',
    message: input.messageText,
    chatId: input.chatId || input.senderId,
    pageId: input.pageId || '',
    instagramAccountId: input.instagramAccountId || '',
    tiktokAccountId: input.tiktokAccountId || '',
    businessConfig: bc,
    inHours: inHours,
    outOfHoursMessage: bc.outOfHoursMessage || 'Estamos fuera de horario. Te responderemos a la brevedad.',
    systemMessage: systemMessage
  }
}];

var ctx = $('Construir Contexto IA').first().json;
var agentOutput = $('Agente IA Multi-Canal').first().json.output || '';

// Limpiar bloque <JSON>...</JSON> de la respuesta al cliente
var cleanResponse = agentOutput.replace(/<JSON>[\s\S]*?<\/JSON>/g, '').trim();

// Extraer intent/confidence del bloque <JSON>
var intent = 'fallback';
var confidence = 0.5;
try {
  var match = agentOutput.match(/<JSON>([\s\S]*?)<\/JSON>/);
  if (match) {
    var parsed = JSON.parse(match[1].trim());
    intent = parsed.intent || 'fallback';
    confidence = parsed.confidence || 0.5;
  }
} catch(e) {}

return [{
  json: {
    platform: ctx.platform,
    tenantId: ctx.tenantId,
    senderId: ctx.senderId,
    chatId: ctx.chatId,
    pageId: ctx.pageId,
    instagramAccountId: ctx.instagramAccountId,
    tiktokAccountId: ctx.tiktokAccountId,
    responseText: cleanResponse,
    intent: intent,
    confidence: confidence,
    inHours: ctx.inHours,
    outOfHoursMessage: ctx.outOfHoursMessage
  }
}];

var ctx = $('Construir Contexto IA').first().json;
return [{
  json: {
    platform: ctx.platform,
    tenantId: ctx.tenantId,
    senderId: ctx.senderId,
    chatId: ctx.chatId,
    pageId: ctx.pageId,
    instagramAccountId: ctx.instagramAccountId,
    tiktokAccountId: ctx.tiktokAccountId,
    responseText: ctx.outOfHoursMessage,
    intent: 'fallback',
    confidence: 1.0,
    inHours: false,
    outOfHoursMessage: ctx.outOfHoursMessage
  }
}];
